title = #{article.title}, summary = #{article.summary}, content = #{article.content}, cover_url = #{article.coverUrl}, category_id = #{article.categoryId}, status = #{article.status}, is_top = #{article.isTop}, update_by = #{article.updateBy}, update_time = #{article.updateTime}
