SELECT a.id, a.title, a.category_id, c.name AS category_name, a.summary, a.cover_url AS cover_image, a.status, a.is_top, a.create_time FROM article a LEFT JOIN category c ON a.category_id = c.id WHERE a.is_deleted = 0 AND c.is_deleted = 0 AND a.create_by = #{currentUserId}
AND a.title LIKE CONCAT('%', #{queryDTO.title}, '%')
AND a.category_id = #{queryDTO.categoryId}
AND a.status = #{queryDTO.status}
ORDER BY a.id DESC
